import type { ScenarioQuestion } from "./types";

function q(id: string, group: string, sub: string, scenario: string, question: string, answer: string, feedback: string, diff: "beginner" | "intermediate" | "advanced"): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: group, subcategory: sub, scenarioPrompt: scenario, question, exampleAnswer: answer, feedback, difficulty: diff };
}

export const expandedBatch3: ScenarioQuestion[] = [
  q("sq-ex3-1","interview_preparation","behavioral","A patient thanks you for excellent care but their outcome was poor.","How do you cope when good care does not lead to good outcomes?","I remind myself that nursing is about the quality of care, not always about the outcome. Some patients have conditions beyond our ability to cure. I focus on the comfort, dignity, and support I provided. I debrief with colleagues and use reflection to process difficult outcomes. Compassion fatigue is real, and I actively practice self-care after difficult cases.","Separating care quality from outcomes and practicing self-care.","intermediate"),
  q("sq-ex3-2","interview_preparation","clinical_judgment","A patient with a pacemaker develops hiccups after eating.","Could hiccups indicate a pacemaker problem?","Persistent hiccups in a pacemaker patient could indicate diaphragmatic pacing—where the pacemaker lead is stimulating the diaphragm. I would assess the timing and pattern of hiccups relative to the pacemaker rhythm, obtain a 12-lead ECG, and notify the cardiologist. This may require lead repositioning or pacemaker reprogramming.","Recognition of uncommon pacemaker complications.","advanced"),
  q("sq-ex3-3","interview_preparation","scenario_responses","A parent asks you to hide the fact that you are giving their child a shot.","How would you handle a parent asking you to deceive their child?","I would explain that honesty builds trust: 'I understand wanting to protect your child from anxiety, but being honest helps them develop coping skills and trust in healthcare providers. I can prepare them gently and use distraction techniques to minimize distress.' I would use age-appropriate language and comfort measures while being truthful about what to expect.","Therapeutic honesty with age-appropriate communication.","beginner"),
  q("sq-ex3-4","workplace_scenarios","prioritization","You have three call lights going off simultaneously.","How would you prioritize three simultaneous call lights?","I would quickly assess which patients are highest acuity from my knowledge of their conditions. If I cannot determine urgency from the desk, I would respond to the most acute patient first and ask the CNA or another nurse to check on the others. If all patients are similar acuity, I would take them in geographic order for efficiency. I would communicate to each patient that help is on the way.","Knowledge-based rapid prioritization with team support.","beginner"),
  q("sq-ex3-5","workplace_scenarios","delegation","You are delegating blood pressure monitoring to a CNA who consistently records values that seem inaccurate.","How would you address consistently inaccurate delegated measurements?","I would approach the CNA privately and validate their blood pressure technique by having them demonstrate on a patient while I listen with my own stethoscope. I would identify specific issues—wrong cuff size, poor positioning, incorrect technique—and provide targeted education. I would follow up with spot-checks until I am confident in their accuracy. This protects both patient safety and the CNA's development.","Competency validation through observation and targeted coaching.","intermediate"),
  q("sq-ex3-6","workplace_scenarios","patient_safety","A new admission arrives and their medication list from home does not match the hospital orders.","How would you handle medication discrepancies at admission?","I would perform thorough medication reconciliation by comparing the patient's home medication list against the admission orders. I would verify with the patient which medications they actually take, including OTC and herbal supplements. Any discrepancies would be flagged to the admitting physician for clarification before administering any medications. Medication reconciliation errors are a leading cause of adverse events.","Systematic medication reconciliation is a critical safety process.","intermediate"),
  q("sq-ex3-7","workplace_scenarios","medication_error","A patient reports feeling 'weird' after receiving a medication they have never had before.","How would you assess a patient reporting unusual symptoms after a new medication?","I would take the report seriously and perform a focused assessment based on the medication's known side effects. I would check vital signs, assess mental status, skin, and respiratory function. I would document the patient's symptoms and the medication details. I would contact the pharmacist about potential reactions and notify the provider. I would prepare for a possible allergic reaction and keep the patient monitored.","Every patient report after new medication administration warrants assessment.","intermediate"),
  q("sq-ex3-8","workplace_scenarios","handoff_communication","You need to give report on a patient you have only had for 2 hours because you received them as a late admission.","How would you give an adequate report on a patient you barely know?","I would be transparent: 'I received this patient as a late admission at 0500 and have limited history with them.' I would share what I know from the admission assessment, chart review, and any interactions during my short time with the patient. I would highlight what I have not yet been able to assess and prioritize the oncoming nurse's first tasks. Transparency about limitations is more valuable than fabricating depth of knowledge.","Transparency about limited patient knowledge is safer than padding the report.","beginner"),
  q("sq-ex3-9","workplace_scenarios","difficult_coworkers","A more experienced nurse corrects your practice in front of a patient in a condescending tone.","How would you handle public correction by a senior colleague?","I would not react defensively in front of the patient. I would say, 'Thank you for the guidance.' After leaving the room, I would speak with the nurse privately: 'I appreciate the feedback, but I would prefer to receive corrections privately so we maintain the patient's confidence in their care team.' If the behavior continued, I would document and escalate.","Maintain composure in the moment, address privately afterward.","intermediate"),
  q("sq-ex3-10","workplace_scenarios","interdisciplinary_communication","You believe a patient would benefit from a consultation with a specialist that has not been ordered.","How would you advocate for a specialist consultation?","I would present my clinical reasoning to the attending physician: 'Based on my assessment, the patient has [specific findings] that may benefit from a [specialist] consultation. Would you consider ordering one?' I would support my suggestion with specific assessment data. If the physician disagrees and I still believe it is warranted, I would document my concern and discuss with the charge nurse.","Clinical data-driven advocacy for appropriate consultations.","intermediate"),
  q("sq-ex3-11","clinical_transition","first_shift","On your first night shift, you hear a loud alarm you do not recognize.","How would you respond to an unfamiliar alarm?","I would go toward the alarm source to investigate rather than ignoring it. I would ask the nearest colleague to help me identify the alarm. I would not silence an alarm until I understand what it is indicating. I would note the type and location of the alarm so I can recognize it in the future. Unfamiliar alarms should always be investigated, never ignored.","Investigate all unfamiliar alarms rather than ignoring them.","beginner"),
  q("sq-ex3-12","clinical_transition","new_nurse_anxiety","You feel like your preceptor is hovering and does not trust you.","How would you address feeling micromanaged by your preceptor?","I would recognize that close supervision early on is normal and protective. However, if I feel ready for more independence, I would have a conversation: 'I appreciate your guidance. As I develop my skills, would you be comfortable letting me take the lead on some assessments while you observe? I want to build my confidence with your support.' Framing it as a growth request is more effective than complaining about micromanagement.","Reframing supervision as supportive rather than distrustful.","beginner"),
  q("sq-ex3-13","clinical_transition","time_management","You spend 20 minutes looking for supplies that were not stocked in the patient's room.","How would you prevent time lost to supply issues?","I would develop a habit of checking room supplies at the start of each shift and during my first round. I would create a standard room setup checklist. I would know where the supply room is and what items are commonly needed. I would report chronic stocking issues to the unit secretary or supply chain coordinator. Preparation time is investment time that pays back throughout the shift.","Proactive supply management saves time during patient care.","beginner"),
  q("sq-ex3-14","clinical_transition","documentation_challenges","You are documenting a complex patient and the EHR system is running slowly.","How would you manage documentation when the EHR is slow?","I would write key findings on a paper brain sheet to ensure I do not lose critical data. I would focus on the most important documentation first—assessment findings, medication administration, and critical notifications. I would report the system issue to IT. I would complete detailed documentation once the system recovers. I would never rely solely on technology without a paper backup strategy.","Paper backup systems for technology failures.","beginner"),
  q("sq-ex3-15","clinical_transition","critical_thinking_drills","A patient's lactate level is 4.2 mmol/L.","What does an elevated lactate indicate?","An elevated lactate suggests tissue hypoperfusion and anaerobic metabolism. In clinical context, this is often associated with sepsis, severe dehydration, hemorrhage, or cardiac failure. I would assess for signs of shock, obtain vital signs, and notify the provider immediately. I would anticipate aggressive IV fluid resuscitation and broad-spectrum antibiotics if sepsis is suspected. Serial lactate measurements track treatment response.","Lactate as an indicator of tissue perfusion and potential sepsis.","intermediate"),
  q("sq-ex3-16","professional_development","professional_boundaries","A patient repeatedly asks about your romantic life and makes you uncomfortable.","How would you handle inappropriate personal questions from a patient?","I would set a clear, firm boundary: 'I appreciate your interest, but I prefer to keep our conversations focused on your care. Is there anything you need right now?' If the behavior continued or escalated to inappropriate comments, I would document it, inform my charge nurse, and discuss having a different caregiver assigned if necessary.","Firm boundary-setting with professional redirection.","beginner"),
  q("sq-ex3-17","professional_development","ethical_dilemmas","A colleague tells you they are going to copy another nurse's care plan because they are too busy to write their own.","How would you respond to a colleague planning to plagiarize care plans?","I would explain that individualized care plans are essential for patient safety—a copied plan may not address the specific patient's needs. I would offer to help them find time-saving templates or resources. If they proceeded anyway, it would be a patient safety concern that I would need to address with the charge nurse. Care plans need to be individualized.","Individualized care plans are not optional—they are patient safety requirements.","intermediate"),
  q("sq-ex3-18","professional_development","workplace_bullying","You are assigned the most difficult patients every shift while other nurses get lighter assignments.","How would you address unfair assignment distribution?","I would track the pattern objectively for several shifts before bringing it up. I would approach the charge nurse with data: 'Over the past two weeks, I have been assigned the highest-acuity patients on 8 of 10 shifts. I want to make sure assignments are being distributed equitably so I can continue to provide quality care.' Objective data is more persuasive than emotional complaints.","Data-driven approach to addressing assignment inequity.","intermediate"),
  q("sq-ex3-19","professional_development","advocacy","A patient is being restrained and you believe the restraints are no longer necessary.","How would you advocate for restraint removal?","I would perform a thorough assessment of the patient's current status—are the criteria for restraints still met? I would document my findings showing the patient no longer meets restraint criteria. I would contact the physician with my assessment and request an order to discontinue restraints. Restraints should be used for the shortest time possible and reassessed frequently. Prolonged unnecessary restraint violates patient rights.","Regular reassessment and advocacy for least restrictive measures.","intermediate"),
  q("sq-ex3-20","professional_development","patient_communication","A patient with limited English asks you to explain their surgery using gestures.","How would you educate a patient when language barriers exist?","I would request a certified medical interpreter rather than relying on gestures alone for surgical education. While waiting for the interpreter, I would use simple visual aids, diagrams, and demonstration where possible. I would never rely on a family member to interpret medical information. I would use a teach-back method through the interpreter to verify understanding.","Certified interpretation for medical discussions, not gesture-based communication.","intermediate"),
  q("sq-ex3-21","career_navigation","job_offer_negotiation","You are interviewing at a facility with a reputation for high turnover.","How would you address high turnover concerns in an interview?","I would ask directly but diplomatically: 'I have heard this unit has experienced some staffing transitions. Can you share what steps have been taken to improve retention and support new staff?' I would assess the answer for specifics—vague reassurances versus concrete changes. High turnover could mean poor management or it could mean a facility working hard to improve. The response tells me a lot about the culture.","Diplomatic inquiry about red flags with assessment of the response quality.","intermediate"),
  q("sq-ex3-22","career_navigation","probation_period","You make a patient very happy and they tell your manager, but your manager does not acknowledge it.","How would you handle unrecognized good performance?","I would not rely on external validation alone—I would maintain an internal record of positive feedback, accomplishments, and successful patient outcomes. When my evaluation comes, I would present this evidence. I would also consider that my manager may express recognition differently. I would focus on consistent quality performance rather than seeking individual praise.","Self-documentation of achievements and internal motivation.","beginner"),
  q("sq-ex3-23","career_navigation","performance_evaluation","Your evaluation suggests you need to improve your delegation skills.","How would you develop delegation skills?","I would start by understanding the scope of practice for each team member. I would practice delegating one additional task per shift that I previously did myself. I would use the five rights of delegation: right task, right circumstance, right person, right direction, right supervision. I would seek feedback from team members about my delegation style and adjust accordingly.","Structured delegation practice using the five rights framework.","intermediate"),
  q("sq-ex3-24","career_navigation","career_advancement","You are interested in nursing informatics as a career path.","How would you explore a career in nursing informatics?","I would start by volunteering to be a super-user for EHR upgrades on my unit. I would join the nursing informatics committee if one exists. I would pursue certification in nursing informatics through ANCC. I would network with informaticists at my facility and explore graduate programs in nursing informatics or health IT. Clinical experience combined with technology skills is the foundation of this specialty.","Building informatics skills through practical involvement and formal education.","intermediate"),
  q("sq-ex3-25","interview_preparation","behavioral","Tell me about how you contribute to a positive team culture.","What do you do to foster team spirit?","I make a point of acknowledging my colleagues' efforts: 'Great catch on that lab value' or 'Thanks for helping me turn that patient.' I bring snacks occasionally, I volunteer to help when I see someone struggling, and I avoid participating in gossip. I believe a positive team culture starts with individual actions, and I try to be the colleague I would want to work alongside.","Specific daily actions that build positive team culture.","beginner"),
  q("sq-ex3-26","interview_preparation","clinical_judgment","A patient with a femoral arterial line has blood pooling under the dressing.","What would you do for a potentially leaking arterial line?","I would apply immediate manual pressure above the dressing at the insertion site. I would call for help, assess the patient's vital signs for hemodynamic compromise, and prepare for a dressing change. I would not remove the dressing without help available, as arterial lines can hemorrhage rapidly. I would assess the patient for signs of hypovolemia and notify the provider.","Arterial line bleeding requires immediate pressure and assistance.","advanced"),
  q("sq-ex3-27","workplace_scenarios","prioritization","You receive lab results showing critical values for two patients simultaneously.","How would you manage two critical lab results at the same time?","I would quickly assess which critical value poses the most immediate life threat. For example, a critically high potassium is more immediately dangerous than a critically low hemoglobin. I would address the most dangerous value first while asking a colleague to notify the other patient's physician. I would document both notifications and follow up on both patients.","Comparative risk assessment for simultaneous critical values.","advanced"),
  q("sq-ex3-28","workplace_scenarios","patient_safety","A visitor brings outside food to a patient who is NPO.","How would you handle unauthorized food delivery to an NPO patient?","I would politely but firmly intervene: 'I appreciate you bringing food for your loved one, but they are not allowed to eat right now due to their upcoming procedure. Eating could make the procedure unsafe. I will need to take the food, but I will make sure it is saved for when they can eat again.' I would educate about aspiration risk and ensure the NPO sign is visible.","Clear communication about NPO importance with aspiration risk education.","beginner"),
  q("sq-ex3-29","clinical_transition","first_shift","A patient codes and you are the closest nurse but have never been first on scene for a code.","How would you respond as first on scene to a code?","I would call a code immediately, start CPR if the patient is pulseless, and call for help. I would follow the basic steps I learned in ACLS/BLS: check responsiveness, call for help, begin compressions. When the code team arrives, I would give a brief report and accept whatever role is assigned to me. After the code, I would debrief with the team and seek feedback on my response.","Immediate life-saving actions with basic training knowledge.","intermediate"),
  q("sq-ex3-30","clinical_transition","time_management","You are trying to complete discharge teaching but the patient keeps going off-topic.","How would you keep discharge teaching focused and efficient?","I would use a structured teaching approach: 'We have four important topics to cover for your safe discharge—medications, activity restrictions, warning signs, and follow-up appointments. Let me walk through each one.' I would redirect gently when the conversation strays: 'That is a great point. Let me finish covering your medications, and then we can discuss that.' I would use a discharge checklist to stay on track.","Structured teaching with gentle redirection.","beginner"),
  q("sq-ex3-31","professional_development","ethical_dilemmas","A patient asks you not to record something they told you in their medical record.","How would you handle a patient requesting information be excluded from their chart?","I would explain that accurate documentation is a legal and professional requirement. I would say, 'I understand your concern about privacy, but documenting your care accurately protects both of us. Medical records are confidential and only accessible to your care team. What specifically concerns you about having this documented?' I would address their underlying fear while maintaining documentation integrity.","Documentation integrity with empathetic exploration of patient concerns.","intermediate"),
  q("sq-ex3-32","professional_development","patient_communication","A family member asks you to explain a complex diagnosis in simple terms.","How would you explain a complex medical condition to a non-medical person?","I would use analogies and simple language. For example, for heart failure: 'Think of the heart like a pump. In heart failure, the pump is not working as strongly as it should, so fluid backs up—kind of like a weak water pump that cannot keep up with the flow. That is why we see swelling and breathing difficulty.' I would check understanding with teach-back and offer written materials.","Use analogies and avoid jargon for health literacy.","beginner"),
  q("sq-ex3-33","career_navigation","career_advancement","You are interested in becoming a nurse manager eventually.","What steps would you take toward nursing management?","I would build leadership skills by taking charge nurse assignments, mentoring new staff, and leading quality improvement projects. I would pursue a BSN and eventually an MSN in nursing leadership or healthcare administration. I would seek mentorship from current nurse managers and observe their leadership style. I would develop skills in conflict resolution, budgeting, staffing, and organizational communication.","Progressive leadership development with formal education.","intermediate"),
  q("sq-ex3-34","interview_preparation","clinical_judgment","A patient on a magnesium drip becomes lethargic with decreased deep tendon reflexes.","What does this suggest and how would you respond?","Decreased deep tendon reflexes and lethargy in a patient on IV magnesium suggests magnesium toxicity. I would immediately stop the magnesium infusion, assess vital signs and respiratory status (magnesium toxicity can cause respiratory arrest), check a stat magnesium level, and notify the provider. Calcium gluconate should be at the bedside as the antidote. I would monitor ECG for cardiac effects.","Recognition of magnesium toxicity with immediate cessation and antidote readiness.","advanced"),
  q("sq-ex3-35","interview_preparation","behavioral","Describe a time when you had to work with limited resources.","How do you manage when resources are constrained?","During a clinical shift when the unit was out of standard wound dressing supplies, I improvised using available materials while maintaining sterile technique. I communicated with the charge nurse about the shortage and helped develop a system for tracking supply levels to prevent future shortages. I learned that resourcefulness is as important as having ideal supplies.","Creative problem-solving with available resources.","intermediate"),
  q("sq-ex3-36","workplace_scenarios","delegation","A CNA you delegated patient feeding to reports the patient is coughing and choking during meals.","How would you respond to a delegation report about swallowing difficulty?","I would assess the patient immediately—coughing and choking during meals suggests aspiration risk and possible dysphagia. I would place the patient on NPO until a swallowing evaluation can be performed. I would notify the provider and request a speech therapy consult. I would thank the CNA for the important observation—their report potentially prevented aspiration pneumonia.","Escalating delegated observations that indicate new clinical problems.","intermediate"),
  q("sq-ex3-37","workplace_scenarios","handoff_communication","During handoff, you discover the patient's code status was changed but not communicated.","How would you handle discovering a code status change during handoff?","I would immediately verify the current code status in the chart and confirm with the provider if there is any ambiguity. I would ensure the correct code status is documented, on the armband, and visible at the bedside. I would communicate the change to all team members. A code status communication failure could result in unwanted resuscitation or inappropriate withholding of treatment—both are serious.","Immediate verification and broad communication of code status changes.","intermediate"),
  q("sq-ex3-38","clinical_transition","critical_thinking_drills","A patient's INR is 1.0 while on warfarin for atrial fibrillation.","What does a subtherapeutic INR mean for this patient?","An INR of 1.0 on warfarin is essentially unprotected—the patient has no anticoagulation benefit and is at risk for stroke. I would notify the provider immediately, anticipate a warfarin dose adjustment, and assess for medication compliance, dietary changes (vitamin K intake), or drug interactions that could explain the low INR. The patient needs bridge anticoagulation consideration.","Understanding therapeutic goals and stroke risk with subtherapeutic anticoagulation.","intermediate"),
  q("sq-ex3-39","professional_development","advocacy","A nurse colleague is being treated unfairly by management and asks for your support.","How would you support a colleague facing unfair treatment?","I would listen to their experience and assess whether I have witnessed the unfair treatment. If I have, I would offer to serve as a witness or provide a written statement. I would encourage them to document incidents and use appropriate channels—HR, union representative, or employee grievance process. I would show solidarity while maintaining professionalism and not engaging in retaliation or gossip.","Supportive witness role with guidance toward proper channels.","intermediate"),
  q("sq-ex3-40","career_navigation","probation_period","You are asked to participate in a unit committee during your probation period.","Should you join a committee during probation?","Joining a committee during probation shows initiative and commitment to the unit. I would choose a committee that aligns with my interests and development goals, such as the patient safety committee or education committee. However, I would balance committee work with my primary focus on clinical competency development. I would discuss the opportunity with my preceptor and manager to ensure the timing is right.","Strategic engagement that shows initiative without overcommitting.","beginner"),
  q("sq-ex3-41","interview_preparation","behavioral","Tell me about your experience with electronic health records.","How comfortable are you with health information technology?","I gained experience with Epic during my clinical rotations, including documentation, order entry, and medication scanning. I am a quick learner with technology and have experience adapting to different EHR systems across clinical sites. I understand the importance of accurate, real-time documentation and the role of technology in patient safety. I am willing to learn any system your facility uses.","Specific EHR experience with adaptability and learning attitude.","beginner"),
  q("sq-ex3-42","interview_preparation","clinical_judgment","A patient with an epidural for pain management reports inability to feel or move their legs.","What complication might this indicate?","While some sensory and motor block is expected with epidural analgesia, complete loss of sensation and motor function may indicate the epidural catheter has migrated into the intrathecal space (high spinal), epidural hematoma, or epidural abscess. I would stop the epidural infusion, perform a neurological assessment, elevate the head of bed, monitor vital signs closely, and notify the anesthesiologist immediately.","Distinguishing normal epidural effects from serious complications.","advanced"),
  q("sq-ex3-43","workplace_scenarios","patient_safety","A patient scheduled for surgery is wearing a ring they refuse to remove.","How would you handle a patient refusing to remove jewelry before surgery?","I would explain the safety reasons: rings can cause thermal burns during cautery, restrict circulation with swelling, and interfere with monitoring. If the patient still refuses, I would document the refusal, tape the ring securely, and notify the surgical team. Some facilities allow taping as an alternative. Patient safety education should be provided without being forceful, but the surgical team needs to make the final decision.","Safety education with alternative solutions when refusal occurs.","beginner"),
  q("sq-ex3-44","clinical_transition","new_nurse_anxiety","You feel anxious every time a physician calls back about a patient.","How would you manage phone call anxiety with physicians?","I would prepare before every physician call using SBAR—having all relevant data in front of me. Preparation reduces anxiety because I know what to say. I would practice with a colleague or preceptor. I would remind myself that physicians appreciate organized, concise communication and that my assessment is valuable. With each successful call, my confidence would grow.","Preparation as the antidote to phone call anxiety.","beginner"),
  q("sq-ex3-45","professional_development","ethical_dilemmas","A patient's family wants to access their adult child's medical information but the patient has not given consent.","How would you handle family requesting adult patient information without consent?","I would explain that adult patients have the right to control who accesses their medical information, even from family members. I would suggest the family talk directly to the patient about including them in their care discussions. If the patient is incapacitated and the family member is the designated health proxy, they may have access rights. I would check the patient's consent forms and HIPAA authorization.","HIPAA compliance even when family dynamics make it uncomfortable.","intermediate"),
  q("sq-ex3-46","interview_preparation","scenario_responses","A patient refuses to let a male nurse provide their care.","How would you handle gender-based care refusal?","I would respect the patient's preference when possible and work with the charge nurse to accommodate the request. Cultural and personal comfort with caregivers is important for the therapeutic relationship. However, if accommodation is not possible due to staffing, I would introduce the male nurse professionally and reassure the patient about their competence. I would never make the patient feel judged for their preference.","Accommodating preferences when possible while maintaining professionalism.","beginner"),
  q("sq-ex3-47","workplace_scenarios","difficult_coworkers","A colleague is consistently late to shifts and you have to stay until they arrive.","How would you address chronic tardiness by a colleague?","I would address it directly the first few times: 'I noticed you have been arriving late, which means I am staying past my shift. Is everything okay?' If it continued, I would document the specific times and report to the charge nurse or manager. I would not clock out before the late nurse arrives, as this would leave patients uncovered. I would also document my extra time for payroll purposes.","Direct communication followed by documentation and escalation.","intermediate"),
  q("sq-ex3-48","clinical_transition","documentation_challenges","You need to chart on a patient you transferred but the patient has already been discharged from your unit in the system.","How would you document after a patient has been transferred out of your care?","I would contact the health information management or IT department to gain access to add a late entry. I would add the entry clearly marked as a late entry with the actual time the care occurred and the current time of documentation. I would explain the reason for the late entry. If I cannot access the chart, I would work with my charge nurse to ensure the documentation is completed through an appropriate mechanism.","Late entry procedures and documentation completion regardless of patient location.","intermediate"),
  q("sq-ex3-49","career_navigation","job_offer_negotiation","You are offered a position with mandatory weekend work every other weekend.","How would you evaluate mandatory weekend requirements?","I would assess whether the weekend schedule is manageable for my personal life. I would ask about flexibility—can I switch weekends with colleagues? Are weekend differentials offered? How far in advance is the schedule posted? Most nursing positions require some weekend work, and understanding the specific expectations helps me plan. I would also consider whether the benefits and compensation offset the scheduling demands.","Realistic assessment of scheduling requirements versus personal needs.","beginner"),
  q("sq-ex3-50","interview_preparation","common_nursing_interview","The interviewer asks: 'How would you handle a conflict with your nurse manager?'","How do you approach conflicts with management?","I would address the conflict directly and professionally by requesting a private meeting. I would present my perspective using specific examples and listen actively to the manager's viewpoint. I would focus on finding a mutually acceptable solution rather than winning the argument. If we could not resolve it together, I would use the facility's conflict resolution process or involve HR if appropriate.","Direct, professional conflict resolution with appropriate escalation.","intermediate"),
  q("sq-ex3-51","interview_preparation","behavioral","Tell me about your self-care practices as a nurse.","How do you prevent burnout?","I maintain firm boundaries between work and home. I exercise regularly, practice mindfulness, and have hobbies outside of nursing. I use my PTO and do not feel guilty about it. I debrief with trusted colleagues after difficult shifts. I also recognize early warning signs of burnout—cynicism, emotional exhaustion, and decreased motivation—and address them proactively rather than pushing through.","Specific, sustainable self-care strategies with self-awareness.","beginner"),
  q("sq-ex3-52","interview_preparation","clinical_judgment","A patient on vancomycin has a trough level come back at 25 mcg/mL.","What does this supratherapeutic vancomycin level mean?","A vancomycin trough of 25 is above the typical therapeutic range of 15-20 mcg/mL, putting the patient at risk for nephrotoxicity and ototoxicity. I would hold the next dose, notify the provider and pharmacist, monitor renal function (creatinine, BUN), assess for hearing changes, and anticipate a dose adjustment. I would ensure adequate hydration and monitor urine output closely.","Supratherapeutic drug level management with toxicity monitoring.","intermediate"),
  q("sq-ex3-53","workplace_scenarios","prioritization","Your shift starts with one patient who needs to go for a CT scan and another who needs pre-op preparation.","How would you prioritize between diagnostic imaging and surgical prep?","I would determine the timing of each: When is the CT scan scheduled? When is the surgery? I would prepare the surgical patient first if their surgery is earlier, as OR delays affect the entire surgical schedule. If both are time-sensitive, I would prepare the surgical patient while delegating transport preparation for the CT patient. I would communicate timelines to both departments.","Coordinating competing departmental timelines with effective delegation.","intermediate"),
  q("sq-ex3-54","workplace_scenarios","medication_error","You administer an IV medication and immediately notice it is running at twice the prescribed rate.","How would you manage an IV rate error you just caught?","I would immediately adjust the rate to the correct setting. I would assess the patient for any adverse effects from the rapid infusion. I would calculate how much extra medication was given and notify the provider with the details. I would file an incident report and review what led to the rate error—perhaps a programming mistake or pump malfunction. I would monitor the patient closely per the medication's profile.","Immediate correction, dose calculation, provider notification, and incident reporting.","intermediate"),
  q("sq-ex3-55","clinical_transition","first_shift","Your badge does not work to access the medication room during your first shift.","How would you handle access issues on your first shift?","I would immediately ask a colleague to let me into the medication room while I contact IT or security about my badge access. I would not try to bypass security systems. I would address the access issue before my next shift so it does not recur. Technical issues on the first shift are common and should not cause panic—just problem-solving.","Practical problem-solving for logistical issues without panic.","beginner"),
  q("sq-ex3-56","clinical_transition","critical_thinking_drills","A patient post-hip replacement has a sudden onset of confusion, petechial rash on the chest, and dyspnea.","What syndrome do these symptoms suggest?","This classic triad—confusion, petechial rash, and dyspnea after a long bone fracture or orthopedic surgery—suggests fat embolism syndrome. I would immediately provide supplemental oxygen, notify the orthopedic surgeon and rapid response team, prepare for emergent imaging, and monitor vital signs continuously. FES typically occurs 24-72 hours post-injury and can be life-threatening.","Recognition of fat embolism syndrome triad in orthopedic patients.","advanced"),
  q("sq-ex3-57","professional_development","professional_boundaries","A former patient contacts you through social media asking for medical advice.","How would you handle a former patient seeking medical advice through social media?","I would not provide medical advice through social media. I would send a brief message: 'Thank you for reaching out. I am not able to provide medical advice through social media. I recommend contacting your primary care provider for guidance.' I would not maintain an ongoing social media relationship with former patients and would adjust my privacy settings accordingly.","No medical advice through social media and maintained professional boundaries.","beginner"),
  q("sq-ex3-58","professional_development","advocacy","You notice that a unit policy disproportionately affects patients from a specific demographic group.","How would you address a potentially inequitable policy?","I would gather data to support my observation—are outcomes different across demographic groups? I would bring my findings to the unit council or manager with specific examples. I would suggest policy review through an equity lens and involve the diversity committee if one exists. Advocacy for health equity is a nursing responsibility, and data-driven approaches are most effective.","Data-driven advocacy for health equity in policy.","advanced"),
  q("sq-ex3-59","career_navigation","performance_evaluation","Your manager asks for your honest assessment of the unit's culture.","How would you provide honest feedback about your workplace?","I would be constructive and specific: 'I appreciate the clinical expertise on our unit. Areas I think we could improve include more consistent communication during handoffs and more support for new graduates during their first year. I would be happy to be part of any solutions.' Honest feedback framed constructively shows maturity and investment in the unit's success.","Constructive honesty that balances positives with specific improvement areas.","intermediate"),
  q("sq-ex3-60","career_navigation","career_advancement","You receive a scholarship opportunity that requires a 3-year work commitment at a rural hospital.","How would you evaluate a scholarship with a service commitment?","I would weigh the financial benefit against the commitment requirements. I would research the specific facility—patient population, available resources, mentorship, and career growth opportunities. Rural nursing offers diverse clinical experience that can be valuable for career development. I would consider whether the commitment timeline aligns with my career plans and personal situation.","Thorough evaluation of financial benefit versus commitment obligations.","intermediate"),
  q("sq-ex3-61","interview_preparation","behavioral","Tell me about a time you advocated for a patient.","Describe your approach to patient advocacy.","During clinical, I noticed an elderly patient was being scheduled for a diagnostic procedure that required NPO status, but they had not been told why or for how long. They were hungry and frustrated. I advocated by clarifying the procedure timing with the physician's office, ensured the patient received a clear explanation, and got the procedure moved up by 2 hours so the NPO period was shorter. The patient was grateful for someone listening.","Specific advocacy action with patient-centered outcome.","beginner"),
  q("sq-ex3-62","workplace_scenarios","delegation","You realize the CNA you delegated vital signs to used the wrong sized blood pressure cuff.","How would you address incorrect equipment use by a delegated team member?","I would first retake the vital signs with the correct cuff size, as inaccurate readings could affect clinical decisions. I would educate the CNA on proper cuff sizing: the bladder should cover 80% of the arm circumference. I would do this privately and supportively, then verify their technique on the next measurement. I would document the corrected readings in the chart.","Immediate correction, re-measurement, and education.","beginner"),
  q("sq-ex3-63","workplace_scenarios","interdisciplinary_communication","The lab calls with a critical value but you are in the middle of an urgent patient situation.","How would you handle receiving a critical lab value during an emergency?","I would ask the lab to hold briefly or ask a nearby colleague to take the call and write down the value. I would not ignore a critical lab call, but my immediate patient's emergency takes priority. As soon as I have a moment, I would review the critical value, assess the patient, and notify the provider. I would document the time I received the value and when I acted on it.","Balancing competing urgent demands with team communication.","intermediate"),
  q("sq-ex3-64","clinical_transition","new_nurse_anxiety","Your friends and family ask you medical questions now that you are a nurse.","How would you handle personal medical questions from friends and family?","I would set boundaries while being helpful: 'I appreciate you trusting me, but I cannot diagnose or prescribe as that is outside my role. I can help you understand information from your doctor or suggest when you should seek medical attention.' I would never diagnose or recommend specific treatments. I would be especially careful about providing medical advice that could be harmful if the situation is more complex than it appears.","Professional boundary maintenance in personal relationships.","beginner"),
  q("sq-ex3-65","professional_development","patient_communication","A patient with a visual impairment needs medication education.","How would you adapt education for a visually impaired patient?","I would use verbal descriptions of medications—shape, size, texture, and smell if applicable. I would provide large-print materials or audio recordings of instructions. I would organize medications by time of day in a pill organizer with tactile markers. I would involve the patient in creating a system that works for them and connect them with visually impaired support services for ongoing help with medication management.","Adaptive education methods for visual impairment.","intermediate"),
  q("sq-ex3-66","interview_preparation","difficult_interviewer","The interviewer seems to be testing your knowledge by asking progressively harder clinical questions.","How would you handle increasingly difficult questions in an interview?","I would answer what I know confidently and honestly admit when I reach my knowledge limit: 'I am not sure of the specific answer to that, but I know I would consult with the pharmacist or look it up in my clinical reference before acting.' Showing my clinical reasoning process and safety-first mindset is more impressive than guessing at answers to advanced questions.","Confident honesty about knowledge boundaries with safe practice emphasis.","advanced"),
  q("sq-ex3-67","workplace_scenarios","medication_error","A patient's medication was changed but the old medication was not discontinued in the MAR.","How would you handle duplicate medication orders?","I would hold both medications and contact the provider to clarify which should be active. I would check the most recent progress notes for documentation of the medication change. I would work with the pharmacist to ensure the MAR is updated correctly. I would file an incident report for the duplicate order and ensure the patient only receives the intended medication.","Clarification before administration when orders conflict.","intermediate"),
  q("sq-ex3-68","clinical_transition","time_management","You realize you have been spending disproportionate time on one patient's family communication.","How would you set time boundaries for family communication?","I would designate a primary family contact and schedule specific times for updates rather than fielding multiple calls throughout the shift. I would provide the family with the physician's callback schedule and direct clinical questions to the appropriate provider. I would document my communication with the family and set expectations for update frequency: 'I will call you at 2 PM with an update.'","Structured family communication that protects patient care time.","intermediate"),
  q("sq-ex3-69","professional_development","workplace_bullying","A group of nurses excludes you from their break time and makes comments when you enter the break room.","How would you handle social exclusion and passive-aggressive behavior?","I would not allow the exclusion to affect my professional behavior or patient care. I would continue to be professional and friendly. I would seek connections with other supportive colleagues. If the behavior was interfering with team communication or patient care, I would document specific incidents and discuss with my manager. I would focus on building my own professional identity independent of social cliques.","Professional resilience with selective escalation when work is affected.","intermediate"),
  q("sq-ex3-70","career_navigation","career_advancement","You are asked to present at a nursing conference for the first time.","How would you prepare for your first professional presentation?","I would choose a topic I am passionate about and have clinical experience with. I would research thoroughly, create clear and visually engaging slides, and practice the presentation multiple times. I would seek feedback from a mentor before the presentation. I would prepare for questions by anticipating what the audience might ask. I would manage my nerves by focusing on sharing knowledge rather than performing.","Preparation, practice, and mentorship for professional speaking.","intermediate"),
  q("sq-ex3-71","interview_preparation","clinical_judgment","A patient with a nasogastric tube has not had any drainage for 6 hours despite continuous suction.","What would you do for an NG tube with no output?","I would first check the NG tube for proper placement by verifying the external marking, auscultating while injecting air, and checking pH of aspirate if possible. I would assess for kinks in the tubing, ensure the suction canister is connected and functioning, and try irrigating the tube with 30 mL normal saline per protocol. I would assess the patient's abdomen for distension and notify the provider if the tube remains non-functional.","Systematic NG tube troubleshooting.","intermediate"),
  q("sq-ex3-72","workplace_scenarios","patient_safety","A visitor brings a pet to the hospital room claiming it is an emotional support animal.","How would you handle an unauthorized animal in a patient room?","I would check facility policy on animal visitation. Most hospitals have specific requirements for therapy animals including vaccination records and handler documentation. If the animal is not approved, I would explain the policy kindly: 'I understand how important your pet is for comfort. Our facility requires advance approval for animal visits. Let me help you with the process for a future visit.' I would arrange for appropriate alternatives for emotional support.","Policy compliance with empathetic alternative suggestions.","beginner"),
  q("sq-ex3-73","clinical_transition","critical_thinking_drills","A patient's respiratory rate is 26 but all other vitals are normal and they appear comfortable.","How would you interpret an isolated tachypnea?","I would not dismiss an elevated respiratory rate even if the patient appears comfortable. Tachypnea can be an early sign of metabolic acidosis, infection, pain, anxiety, or pulmonary embolism. I would assess oxygen saturation, listen to lung sounds, ask about pain or anxiety, review recent labs for metabolic abnormalities, and monitor the trend. If it is new, I would notify the provider.","Respiratory rate as an early warning sign that should not be dismissed.","intermediate"),
  q("sq-ex3-74","professional_development","ethical_dilemmas","You are asked to participate in a medical procedure that you have moral objections to.","How would you handle a conflict between professional duties and personal morals?","I would review my facility's conscientious objection policy. I would inform my manager of my objection as early as possible so alternative coverage can be arranged. I would not impose my beliefs on the patient or interfere with their right to receive legal medical treatment. I would ensure the patient receives the same quality of care from another provider. My objection should not delay or impede patient care.","Proper conscientious objection with patient care continuity.","advanced"),
  q("sq-ex3-75","career_navigation","performance_evaluation","You receive feedback that you need to be more assertive in advocating for patients.","How would you develop assertiveness skills?","I would practice using assertive communication techniques: stating concerns clearly with 'I' statements, presenting objective data to support my position, and using CUS words (Concerned, Uncomfortable, Safety) when escalating. I would role-play difficult conversations with a mentor. I would start with lower-stakes situations to build confidence. I would read about assertiveness in healthcare and attend a communication skills workshop.","Specific assertiveness techniques applicable to clinical settings.","intermediate"),
  q("sq-ex3-76","interview_preparation","behavioral","Tell me about a time you went above standard protocol to help a patient.","When have you exceeded expectations in care delivery?","A patient was being discharged after a lengthy hospitalization and was visibly anxious about going home. Beyond the standard discharge process, I arranged a follow-up phone call for the next day, created a personalized checklist of daily care activities, coordinated with the outpatient clinic to ensure a smooth transition, and wrote a personal note of encouragement. The patient called back to say the personal touch made all the difference in their recovery.","Going beyond protocol with creative, personalized care.","beginner"),
  q("sq-ex3-77","workplace_scenarios","interdisciplinary_communication","An occupational therapist disagrees with your assessment of a patient's functional independence.","How would you resolve differing professional assessments?","I would schedule a time to discuss our assessments together, sharing the specific observations and criteria each of us used. I would recognize that OT and nursing assessments measure different aspects of function and both have value. I would propose a joint bedside assessment to observe the patient's function together. The combined assessment would provide a more complete picture for the discharge plan.","Joint assessment to resolve differing professional perspectives.","intermediate"),
  q("sq-ex3-78","clinical_transition","documentation_challenges","You realize that a verbal order you received was never formally entered into the system.","How would you address an unrecorded verbal order?","I would contact the physician to remind them to enter the order. If the physician is unavailable, I would document the verbal order with a read-back per facility protocol and ensure it is countersigned within the required timeframe. I would not continue executing an order that is not formally documented, as this creates a legal and safety gap.","Verbal order documentation requirements and follow-up.","intermediate"),
  q("sq-ex3-79","professional_development","patient_communication","A patient's family is arguing at the bedside and it is upsetting the patient.","How would you address family conflict at the bedside?","I would calmly intervene: 'I can see this is an emotional time. I am concerned about how this is affecting your loved one's rest and recovery. Would you like to step into the family room to continue your discussion?' I would check on the patient afterward to assess their emotional state. If the conflict is recurring, I would involve social work for family support and mediation.","De-escalating family dynamics to protect patient wellbeing.","beginner"),
  q("sq-ex3-80","career_navigation","probation_period","Your manager gives you informal negative feedback midway through probation.","How would you respond to informal negative feedback during probation?","I would take the feedback seriously and thank my manager for being honest. I would ask for specific examples and clarification on expectations. I would create an immediate action plan to address the concerns and check in regularly with my manager to demonstrate improvement. I would document the feedback and my response. Informal feedback during probation is actually an opportunity—it means the manager wants to help me succeed.","Proactive response to feedback during a critical period.","beginner"),
  q("sq-ex3-81","interview_preparation","clinical_judgment","A patient with diabetes has a blood glucose of 450 mg/dL with Kussmaul respirations.","What does this presentation suggest?","This presentation suggests diabetic ketoacidosis—a medical emergency. Kussmaul respirations are the body's attempt to compensate for metabolic acidosis by blowing off CO2. I would check for ketones in blood or urine, obtain a basic metabolic panel and ABG, start IV fluids per protocol, anticipate an insulin drip, monitor potassium closely (insulin drives potassium into cells), and notify the provider immediately.","DKA recognition with systematic emergency management.","advanced"),
  q("sq-ex3-82","workplace_scenarios","handoff_communication","You are giving report and the oncoming nurse seems distracted and is not asking questions.","How would you ensure the receiving nurse is engaged during handoff?","I would pause and make eye contact: 'I want to make sure you have everything you need for these patients. Can I go over the key priorities for the shift?' I would highlight the most critical information and ask specific questions: 'Do you have any questions about Mr. Jones's hemodynamic monitoring plan?' If they still seem disengaged, I would provide a written summary of key information and follow up via message.","Active engagement strategies during handoff.","intermediate"),
  q("sq-ex3-83","clinical_transition","new_nurse_anxiety","You feel like you are constantly being watched and evaluated.","How would you cope with the feeling of constant evaluation?","I would reframe the observation as support rather than surveillance. My preceptor and colleagues are watching because they want me to succeed and want to ensure patients are safe. I would ask for specific feedback: 'I noticed you were watching during that procedure—do you have any suggestions for me?' Turning observation into learning opportunities reduces anxiety and demonstrates a growth mindset.","Reframing evaluation as supportive mentorship.","beginner"),
  q("sq-ex3-84","professional_development","ethical_dilemmas","A dying patient wants to donate organs but their family objects to donation.","How would you navigate organ donation with family resistance?","I would refer to the organ procurement organization, as they have trained coordinators for these conversations. I would support the patient's registered donation status—in many jurisdictions, the patient's documented wishes take legal precedence over family objections. I would provide the family with information about organ donation and support them emotionally. I would ensure the patient's autonomy is respected.","Proper referral to organ procurement with patient autonomy focus.","advanced"),
  q("sq-ex3-85","career_navigation","career_advancement","You are interested in becoming a travel nurse after gaining some experience.","What factors should you consider before travel nursing?","I would consider: minimum experience requirements (usually 1-2 years in a specialty), comfort with independent practice across different facilities, licensing requirements across states, housing and tax implications, contract terms and cancellation policies, the impact on professional relationships and career continuity, and my personal readiness for frequent change. I would start with local per diem work to test my adaptability.","Comprehensive assessment of readiness for travel nursing.","intermediate"),
  q("sq-ex3-86","interview_preparation","scenario_responses","A patient asks you to witness a document but you are unsure if you should.","How would you handle a request to witness a document?","I would first determine what I am being asked to witness. I can witness a patient's signature on hospital forms within facility policy. However, I would not witness legal documents like wills without checking with my charge nurse and facility legal department. I would explain that some documents require specific legal witnesses and suggest they contact the appropriate legal resources.","Understanding witness role limitations and proper legal guidance.","intermediate"),
  q("sq-ex3-87","workplace_scenarios","patient_safety","A confused patient keeps removing their telemetry monitor leads.","How would you maintain cardiac monitoring on a patient who removes leads?","I would assess why the patient is removing the leads—are they itchy, uncomfortable, or is the patient confused? I would try different lead placements or hypoallergenic patches. I would provide a sitter if available. I would cover the leads with a gown or wrap to reduce access. I would discuss with the provider whether a modified monitoring approach is appropriate for this patient.","Creative solutions for maintaining essential monitoring.","intermediate"),
  q("sq-ex3-88","clinical_transition","critical_thinking_drills","A patient's troponin is mildly elevated but they have chronic kidney disease.","How does renal function affect troponin interpretation?","Chronic kidney disease can cause chronically elevated troponin levels without acute cardiac injury. However, elevated troponin should never be automatically attributed to CKD without clinical correlation. I would assess for cardiac symptoms, compare to previous troponin values if available, obtain serial troponins to assess for trending, and obtain an ECG. The clinical picture, not just the lab value, determines the significance.","Contextual lab interpretation considering comorbid conditions.","advanced"),
  q("sq-ex3-89","professional_development","advocacy","A patient is being discharged with a new prescription but the outpatient pharmacy is closed.","How would you ensure medication access at discharge?","I would not discharge a patient without access to essential medications. I would contact the inpatient pharmacy about providing a bridge supply. I would check if 24-hour pharmacies nearby can fill the prescription. I would explore mail-order pharmacy options. I would provide samples from the physician's office if available. I would delay discharge until medication access is confirmed for time-critical medications.","Ensuring medication access before completing discharge.","intermediate"),
  q("sq-ex3-90","career_navigation","performance_evaluation","You want to ask for a raise at your annual evaluation.","How would you approach salary negotiation during your evaluation?","I would prepare a portfolio of my accomplishments: certifications obtained, committees served on, quality metrics I have contributed to, positive patient feedback, and additional responsibilities I have taken on. I would research salary benchmarks for my experience level and location. I would present my request based on my demonstrated value: 'Based on my contributions this year and market rates, I believe a salary adjustment to $X is appropriate.'","Value-based salary negotiation with documented contributions.","intermediate"),
  q("sq-ex3-91","interview_preparation","behavioral","Tell me about a time you showed creativity in problem-solving.","When have you used creative thinking in a clinical situation?","A patient with dementia was refusing all oral medications by clamping their mouth shut. After consulting with the pharmacist, I discovered that three of the medications came in alternative forms—liquid, patch, and sublingual. For the remaining pills, we received physician approval to crush them and mix with applesauce. By the end of the shift, the patient had received all their medications. The key was looking beyond the standard approach.","Creative problem-solving within safe clinical parameters.","intermediate"),
  q("sq-ex3-92","workplace_scenarios","delegation","You need to delegate specimen collection to a CNA but there are specific timing requirements.","How would you delegate time-sensitive specimen collection?","I would give very specific instructions: 'I need a clean-catch urine specimen from Mrs. Lee in room 310 collected before her 2 PM antibiotic dose. Please label it with two patient identifiers, note the collection time, and bring it directly to me. If she is unable to provide a specimen, please let me know by 1:30 so we can adjust the plan.' Clear parameters and a backup plan ensure task completion.","Specific timing parameters and backup planning in delegation.","beginner"),
  q("sq-ex3-93","clinical_transition","documentation_challenges","You need to document patient education but are unsure how much detail to include.","How detailed should patient education documentation be?","I would document: what was taught, the method used (verbal, written, video, demonstration), who was present (patient, family members), the patient's response and level of understanding assessed through teach-back, any barriers identified (language, cognitive, health literacy), and plans for reinforcement. I would avoid documenting 'patient taught' without demonstrating that learning occurred. Evidence of assessment of understanding is key.","Comprehensive education documentation that demonstrates assessment of learning.","beginner"),
  q("sq-ex3-94","professional_development","patient_communication","A patient asks you directly: 'Am I going to be okay?'","How would you respond to a patient asking about their prognosis?","I would be honest while remaining within my scope. I might say, 'Your care team is working hard to give you the best possible outcome. The doctor will be the best person to discuss your specific prognosis. What concerns do you have that I can help address right now?' I would not make prognostic statements outside my scope but would ensure the patient's concerns are communicated to the physician for a timely discussion.","Honest, scope-appropriate response with physician referral.","intermediate"),
  q("sq-ex3-95","interview_preparation","clinical_judgment","A patient develops stridor and drooling after a tonsillectomy.","What postoperative complication does this suggest?","Stridor and drooling after tonsillectomy suggest airway compromise—either from swelling, hematoma formation, or post-operative bleeding obstructing the airway. This is an emergency. I would position the patient sitting upright, call for help immediately, prepare suction, and have emergency airway equipment at bedside. I would notify the surgeon STAT. The patient may need emergent return to the OR.","Airway emergency recognition in post-tonsillectomy patients.","advanced"),
  q("sq-ex3-96","workplace_scenarios","patient_safety","A patient is about to be transported for a procedure but their consent form is not signed.","How would you handle missing consent before a procedure?","I would not allow the patient to be transported until informed consent is obtained. I would notify the physician to come discuss the procedure with the patient and obtain consent. If the physician is already in the procedure suite, I would communicate the delay. Proceeding without proper informed consent is both unethical and illegal, regardless of scheduling pressure.","Never transport for a procedure without proper consent.","beginner"),
  q("sq-ex3-97","clinical_transition","time_management","You are struggling to find time for bathroom breaks during your shift.","How would you address being unable to take breaks?","I would make breaks a priority rather than an afterthought. I would schedule a specific time for a break and ask a colleague for coverage. I would communicate with the charge nurse if workload consistently prevents breaks. Going without bathroom breaks or meals is unsafe—it leads to dehydration, fatigue, and cognitive decline that can cause errors. Self-care is patient safety.","Breaks as a patient safety issue, not a luxury.","beginner"),
  q("sq-ex3-98","professional_development","workplace_bullying","A senior nurse tells you that your nursing school did not prepare you adequately.","How would you respond to criticism of your nursing education?","I would not take the bait. I might say, 'I received a solid foundation in nursing school, and I am excited to build on it with hands-on experience here. Every program has strengths and areas that clinical practice fills in. I am here to learn and grow.' I would not argue about the quality of my education—my clinical performance would speak for itself over time.","Confident, non-defensive response to education criticism.","beginner"),
  q("sq-ex3-99","career_navigation","probation_period","You discover that other new grads on your unit are receiving better orientation support.","How would you address unequal orientation experiences?","I would advocate for myself by speaking with my nurse educator: 'I have noticed some differences in orientation structure, and I want to make sure I am getting the support I need to succeed. Could we review my orientation plan and identify any gaps?' I would request specific resources or experiences I feel I am missing. Advocating for equitable orientation is appropriate self-advocacy.","Self-advocacy for equitable orientation support.","intermediate"),
  q("sq-ex3-100","interview_preparation","behavioral","Tell me about a time you had to be flexible and adapt your plan.","Describe your adaptability in a clinical situation.","I had planned a thorough morning routine for my clinical day, but when I arrived, one of my patients had been upgraded to a higher acuity level overnight, and a new admission was waiting. I quickly restructured my priorities, delegated non-essential tasks, and focused on the most critical needs first. By mid-shift, I had caught up with all my planned activities. I learned that adaptability is not about abandoning your plan—it is about reprioritizing intelligently.","Specific example of adaptive planning under changing conditions.","beginner"),
  q("sq-ex3-101","interview_preparation","clinical_judgment","A patient with a tracheostomy becomes decannulated and you cannot reinsert the tube.","What would you do if a tracheostomy tube falls out and cannot be replaced?","This is an airway emergency. I would call for help immediately. If the tracheostomy is recent (less than 7 days), the stoma may close rapidly, so I would attempt to ventilate through the mouth and nose while covering the stoma. If the trach is mature, I could try inserting a smaller trach or an endotracheal tube through the stoma. I would use bag-valve-mask ventilation as a bridge and prepare for emergent reintubation.","Managing tracheostomy emergencies with alternative ventilation strategies.","advanced"),
  q("sq-ex3-102","workplace_scenarios","difficult_coworkers","A colleague frequently asks you to swap shifts at the last minute, disrupting your personal plans.","How would you set boundaries around last-minute shift swaps?","I would be honest and kind: 'I am happy to swap shifts when I can plan for it, but last-minute swaps are difficult for me to accommodate. Could you give me more notice next time? If it is at least a few days in advance, I am much more likely to be able to help.' I would not feel guilty about protecting my personal time—boundaries are healthy and prevent resentment.","Clear boundary-setting with offered alternatives.","beginner"),
  q("sq-ex3-103","clinical_transition","critical_thinking_drills","A patient's albumin level is 2.1 g/dL.","What is the clinical significance of hypoalbuminemia?","An albumin of 2.1 indicates severe hypoalbuminemia, suggesting malnutrition, liver disease, nephrotic syndrome, or chronic inflammation. Clinically, this means the patient is at high risk for pressure injuries, poor wound healing, and fluid imbalance (third-spacing edema). Drug binding is also affected, making some medications more potent. I would consult nutrition services, assess skin integrity frequently, and communicate the finding to the care team.","Connecting albumin to clinical risks and anticipatory interventions.","intermediate"),
  q("sq-ex3-104","professional_development","ethical_dilemmas","A patient asks you to lie to their employer about the reason for their hospitalization.","How would you handle a patient asking you to provide false information?","I would explain that I cannot provide false medical information, as it would be dishonest and could create legal liability for both of us. I would help the patient understand their privacy rights—their employer is not entitled to specific diagnosis information. I would offer to provide a generic work excuse that states they were hospitalized without disclosing details. HIPAA protects their medical privacy from employers.","Honest refusal with helpful alternatives that protect privacy.","intermediate"),
  q("sq-ex3-105","career_navigation","career_advancement","You want to publish your quality improvement project findings.","How would you prepare a manuscript for nursing publication?","I would identify appropriate nursing journals for my topic and review their submission guidelines. I would structure my paper following the standard QI format: introduction, methods, results, and discussion. I would seek co-authorship with my QI mentor who has publication experience. I would have colleagues review the manuscript before submission. Getting published as a bedside nurse strengthens your professional profile and contributes to evidence-based practice.","Step-by-step approach to nursing publication.","advanced"),
  q("sq-ex3-106","interview_preparation","behavioral","Describe how you handle uncertainty in clinical situations.","How do you manage clinical uncertainty?","When I encounter clinical uncertainty, I follow a systematic approach: I gather more data through thorough assessment, consult with colleagues and reference materials, communicate my concerns to the physician clearly, and document my thinking process. I never pretend to be certain when I am not. I find that uncertainty, when managed well, leads to better clinical outcomes because it prompts more thorough investigation.","Systematic approach to uncertainty with emphasis on safety.","intermediate"),
  q("sq-ex3-107","workplace_scenarios","interdisciplinary_communication","The night shift physician gives orders that conflict with the day team's plan of care.","How would you manage conflicting orders from different physicians?","I would not implement conflicting orders. I would clarify with the night physician: 'I notice this order differs from the day team's plan. Can you help me understand the rationale for the change?' I would document the communication and ensure the day team is informed at shift change. If the orders directly conflict, I would ask the physicians to communicate and reconcile the plan.","Clarification and reconciliation of conflicting orders.","intermediate"),
  q("sq-ex3-108","clinical_transition","first_shift","You finish your first shift feeling exhausted but accomplished.","How would you develop healthy post-shift routines?","I would establish a consistent post-shift routine: change out of scrubs, take a shower to transition mentally, eat a healthy meal, debrief briefly about the shift (journal or talk to someone), then engage in a relaxing activity. I would avoid scrolling through medical information or replaying the shift endlessly. Quality sleep after a shift is essential—I would optimize my sleep environment and set firm boundaries.","Structured transition routines for physical and mental recovery.","beginner"),
  q("sq-ex3-109","professional_development","patient_communication","A patient with aphasia is trying to communicate a need to you.","How would you communicate with a patient who has aphasia?","I would be patient and give them time to express themselves. I would use communication tools: picture boards, writing materials, yes/no questions, or speech therapy-recommended strategies. I would observe nonverbal cues including pointing, gestures, and facial expressions. I would consult with the speech therapist about the most effective communication methods for this specific patient. I would never pretend to understand when I do not—I would keep trying different approaches.","Patient communication tools and speech therapy collaboration.","intermediate"),
  q("sq-ex3-110","career_navigation","job_offer_negotiation","You are offered a sign-on bonus with a relocation package.","How would you evaluate a relocation package?","I would evaluate the total relocation package: moving expenses covered, temporary housing provisions, travel reimbursement, and any settling-in allowance. I would factor in cost-of-living differences between locations. I would ask about licensure transfer support and timeline. I would consider the personal impact of relocation on family and support systems. I would negotiate for items not included—temporary housing extension, return trips home during orientation, or partner job search support.","Comprehensive relocation package evaluation beyond moving costs.","intermediate"),
  q("sq-ex3-111","interview_preparation","star_examples","Tell me about a time you identified a safety hazard.","Describe how you identified and addressed a safety risk.","During my clinical rotation, I noticed that the hand sanitizer dispenser outside a contact isolation room was empty and had been for the entire shift. I immediately refilled it and then tracked the restocking schedule, discovering that some dispensers were being missed systematically. I created a simple checklist and proposed it to the unit manager. The checklist was implemented unit-wide, and hand hygiene compliance improved.","Identifying a systemic safety gap and implementing a solution.","beginner"),
  q("sq-ex3-112","workplace_scenarios","medication_error","A nurse accidentally drops a controlled substance on the floor during preparation.","How would you handle a dropped controlled substance?","I would follow facility policy for controlled substance waste, which typically requires a witness. I would document the dropped medication, have another nurse witness the disposal, and re-obtain the medication from the dispensing system. I would document the waste properly to maintain accurate controlled substance counts. Every controlled substance discrepancy must be properly documented and witnessed.","Proper controlled substance waste with witnessed documentation.","beginner"),
  q("sq-ex3-113","clinical_transition","critical_thinking_drills","A patient on warfarin develops dark, tarry stools.","What does melena indicate in an anticoagulated patient?","Dark, tarry stools (melena) indicate upper gastrointestinal bleeding—likely from the esophagus, stomach, or duodenum. In a patient on warfarin, this is a significant complication. I would check vitals for hemodynamic instability, obtain a stat INR and CBC, hold the warfarin, notify the provider immediately, and prepare for possible endoscopy. I would establish large-bore IV access and type and crossmatch for possible transfusion.","Melena recognition in anticoagulated patients with emergency preparation.","intermediate"),
  q("sq-ex3-114","professional_development","advocacy","A patient asks for help understanding their insurance denial letter.","How would you help a patient navigate insurance issues?","I would acknowledge that insurance letters can be confusing and offer to help them understand the basic information—what was denied and why. I would then connect them with the appropriate resource: the hospital's financial counselor, social worker, or patient advocate who specializes in insurance navigation. I would ensure they know about their right to appeal and the timeline for doing so.","Empathetic guidance with proper referral for specialized insurance help.","beginner"),
  q("sq-ex3-115","career_navigation","career_advancement","You are considering whether to pursue your DNP or PhD in nursing.","How would you decide between DNP and PhD?","The DNP focuses on clinical practice, leadership, and translating evidence into practice—ideal for advanced clinical roles, executive leadership, or systems improvement. The PhD focuses on generating new knowledge through research—ideal for academic careers and research leadership. I would consider my ultimate career goal: if I want to practice or lead in clinical settings, DNP is appropriate. If I want to conduct research and teach at the university level, PhD is the path.","Understanding distinct purposes of terminal nursing degrees.","advanced"),
  q("sq-ex3-116","interview_preparation","scenario_responses","A patient asks you if their nurse from the previous shift made a mistake.","How would you respond to a patient questioning a previous nurse's care?","I would not comment on another nurse's practice. I would say, 'I cannot speak to what happened on the previous shift, but I want to make sure you receive the best care going forward. Can you tell me what concerns you have so I can address them?' If the patient describes something that sounds like a genuine error, I would investigate through chart review and report my findings to the charge nurse.","Neutral response with forward-focused care and proper investigation.","intermediate"),
  q("sq-ex3-117","workplace_scenarios","delegation","You delegate wound measurement to an LPN who you know is skilled in wound care.","How would you follow up on delegated wound care?","I would review the LPN's wound assessment documentation for completeness and accuracy. I would compare measurements to previous assessments to evaluate wound progression. I would discuss any changes or concerns with the LPN and collaborate on updating the wound care plan. Even when delegating to skilled team members, the RN retains accountability for the overall plan of care.","RN accountability for delegated assessments even to skilled team members.","intermediate"),
  q("sq-ex3-118","clinical_transition","new_nurse_anxiety","You feel like you are bothering your preceptor every time you ask a question.","How would you overcome the fear of asking too many questions?","I would remind myself that questions are how I learn and keep patients safe. My preceptor expects questions during orientation—that is their role. I would batch non-urgent questions to ask at appropriate times rather than interrupting during critical tasks. I would prioritize urgent clinical questions that need immediate answers. I would also self-study to reduce questions about things I can look up on my own.","Strategic questioning that balances learning with independence.","beginner"),
  q("sq-ex3-119","professional_development","ethical_dilemmas","A researcher asks you to enroll your patients in a study without adequate informed consent.","How would you handle pressure to enroll patients in research unethically?","I would refuse to participate in research that does not follow proper informed consent procedures. I would report the concern to the IRB and my manager. Every patient has the right to fully understand what they are consenting to before participating in research. I would not facilitate enrolling patients without proper consent regardless of who is asking.","Firm ethical stance on research ethics and proper reporting.","advanced"),
  q("sq-ex3-120","career_navigation","performance_evaluation","Your evaluation is good overall but notes you need to improve attendance.","How would you address attendance concerns?","I would take the feedback seriously and review my attendance record objectively. If absences were due to genuine illness, I would explain the context and ask about available support like flexible scheduling or EAP services. I would set a concrete attendance goal for the next period and implement strategies like self-care to reduce sick days. I would show commitment to improvement through consistent attendance going forward.","Honest self-assessment with actionable attendance improvement plan.","beginner"),
];
